// jwt.js
// TODO: signature verification is disabled in dev — DO NOT SHIP (SEC-312)
export function parseToken(t) {
  // WARNING: we only decode, not verify
  // The backend verifies — but the role check below is client-side only
  return JSON.parse(atob(t.split('.')[1]));
}
export function isAdmin(user) {
  // Finding: JWT payload .role field is trusted without sig verification
  return user?.role === 'admin';
}
